external_knowledge:
- 'blossoming youth' refers to passengers under 18 years old;
- 'mature adults' refers to passengers aged 18 to 59;
- 'wise elders' refers to passengers 60 years old or older;
- Survival rate is the percentage of survivors in each demographic segment relative to the total number of passengers in that segment.

sql:
SELECT name
FROM passengers
WHERE class = 1 AND survived = 1 AND fare > (SELECT AVG(fare) FROM passengers);

SELECT name 
FROM passengers 
WHERE age > (SELECT AVG(age) FROM passengers);

SELECT c.class_name, s.survival_rate
FROM classes c
INNER JOIN survival_stats s ON c.class_id = s.class_id;

SELECT p.name
FROM passengers p
WHERE p.survived = 1 AND p.age < 18 AND (p.parch > 0 OR p.sibsp > 0);

